# -*- coding: utf-8 -*-
import re, zipfile, html
from pathlib import Path

def docx_text(path):
    with zipfile.ZipFile(path) as z:
        xml = z.read('word/document.xml').decode('utf-8', errors='ignore')
    text = re.sub(r'</w:p>', '\n', xml)
    return re.sub(r'<[^>]+>', '', text)

desk = Path(r'C:\Users\cherkasov.n\Desktop')
for f in desk.rglob('*.docx'):
    try:
        t = docx_text(f)
        if re.search('pronsk|Пронск|ING11|buhport|user13', t, re.I):
            print('DOCX:', f)
            for line in t.splitlines():
                if re.search('pronsk|Пронск|ING11|buhport|user13|бухгалтер', line, re.I):
                    print(' ', line.strip()[:200])
    except Exception:
        pass

for x in desk.rglob('*.xlsx'):
    with zipfile.ZipFile(x) as z:
        blob = ''.join(z.read(n).decode('utf-8', errors='ignore') for n in z.namelist() if n.endswith('.xml'))
    if 'pronskiy' not in blob.lower():
        continue
    print('XLSX:', x)
    for m in re.finditer(r'<row r="(\d+)"[^>]*>(.*?)</row>', blob, re.S):
        if 'pronskiy' not in m.group(2).lower():
            continue
        cells = []
        for c in re.findall(r'<c r="([A-Z]+\d+)"[^>]*>(?:<v>(.*?)</v>|<is><t>(.*?)</t></is>)', m.group(2), re.S):
            val = c[2] if c[2] else c[1]
            val = html.unescape(re.sub(r'<[^>]+>', '', val))
            cells.append(f'{c[0]}={val}')
        print(' ROW', m.group(1), ' | '.join(cells))

for f in [desk / '1.html']:
    if f.exists():
        t = f.read_text(encoding='utf-8', errors='ignore')
        for pat in ['pronskiy', 'ING11', 'buhport', 'user13', 'Пронск']:
            if pat.lower() in t.lower():
                print('HTML hit', pat)
                for m in re.finditer(r'.{0,80}' + re.escape(pat) + r'.{0,120}', t, re.I):
                    print(' ', re.sub(r'\s+', ' ', m.group(0))[:220])

